import React, { useState } from 'react';
import { db } from '../firebase'; 
import { collection, query, where, getDocs } from 'firebase/firestore';
import { User, Lock, ShieldCheck, ArrowRight, AlertCircle, LayoutGrid } from 'lucide-react';

function Login({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleAuth = async (e) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const formattedUsername = username.trim().toLowerCase();
      const usersRef = collection(db, "users");
      const q = query(usersRef, where("username", "==", formattedUsername), where("password", "==", password));
      const querySnapshot = await getDocs(q);

      if (!querySnapshot.empty) {
        const userData = querySnapshot.docs[0].data();
        localStorage.setItem('user_info', JSON.stringify({ 
          name: userData.fullName || formattedUsername.toUpperCase(), 
          role: userData.role || 'student', 
          username: userData.username || formattedUsername
        }));

        const userRole = (userData.role || "").toLowerCase();
        if (userRole === 'admin' || formattedUsername === 'admin') {
          onLogin('admin'); 
        } else {
          onLogin('student'); 
        }
      } else {
        setError("Invalid username or password.");
      }
    } catch (err) {
      setError("Failed to connect to the database.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen bg-[#0a0a0a] font-sans selection:bg-indigo-500/30 overflow-hidden">
      
      {/* ⬅️ LEFT SIDE: BRANDING (Hidden on Mobile) */}
      {/* 'hidden' hides it by default. 'md:flex' shows it on screens larger than 768px */}
      <div className="hidden md:flex flex-col justify-center items-center w-1/2 relative border-r border-white/10 bg-[#050505] p-12">
        <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-indigo-600/10 blur-[120px] rounded-full"></div>
        
        <div className="relative z-10 text-center flex flex-col items-center">
          <div className="w-20 h-20 bg-gradient-to-tr from-indigo-500 to-purple-600 rounded-[1.5rem] flex items-center justify-center shadow-2xl mb-8 border border-white/20">
            <LayoutGrid className="w-10 h-10 text-white" />
          </div>
          <h1 className="text-5xl font-extrabold text-white tracking-tight mb-4">CampusCanvas</h1>
          <p className="text-gray-400 text-lg max-w-sm">Institutional Project Repository</p>
        </div>
      </div>

      {/* ➡️ RIGHT SIDE: LOGIN FORM (Full width on Mobile) */}
      <div className="flex flex-col justify-center items-center w-full md:w-1/2 p-6 sm:p-12 relative">
        
        {/* Mobile Header (Visible only on Mobile) */}
        <div className="md:hidden flex flex-col items-center mb-10">
          <div className="w-12 h-12 bg-indigo-600 rounded-xl flex items-center justify-center mb-4">
             <LayoutGrid className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-white">CampusCanvas</h1>
        </div>

        <div className="w-full max-w-md bg-white/5 backdrop-blur-xl border border-white/10 p-8 sm:p-10 rounded-[2.5rem] shadow-2xl">
          
          <div className="text-center mb-8">
            <h2 className="text-3xl font-bold text-white mb-2">Sign In</h2>
            <p className="text-gray-400 text-sm">Enter your credentials to continue</p>
          </div>

          {error && (
            <div className="bg-red-500/10 border border-red-500/30 text-red-400 p-4 rounded-xl mb-6 text-sm flex items-center gap-2">
              <AlertCircle className="w-5 h-5 shrink-0" /> {error}
            </div>
          )}

          <form onSubmit={handleAuth} className="space-y-5">
            <div>
              <label className="block text-sm font-semibold text-gray-400 mb-2 ml-1">Username / Roll No.</label>
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                <input 
                  type="text" 
                  value={username} 
                  onChange={(e) => setUsername(e.target.value)} 
                  className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-4 text-white outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all placeholder-gray-600"
                  placeholder="23bsccs01"
                  required
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-400 mb-2 ml-1">Password</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                <input 
                  type="password" 
                  value={password} 
                  onChange={(e) => setPassword(e.target.value)} 
                  className="w-full bg-white/5 border border-white/10 rounded-2xl pl-12 pr-4 py-4 text-white outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all placeholder-gray-600"
                  placeholder="••••••••"
                  required
                />
              </div>
            </div>

            <button 
              type="submit" 
              disabled={isLoading}
              className={`w-full mt-4 py-4 rounded-2xl font-bold text-lg flex justify-center items-center gap-2 transition-all ${isLoading ? 'bg-gray-700 text-gray-500 cursor-not-allowed' : 'bg-indigo-600 text-white hover:bg-indigo-500 shadow-lg hover:shadow-indigo-500/20 active:scale-[0.98]'}`}
            >
              {isLoading ? 'Processing...' : <>Secure Login <ArrowRight className="w-5 h-5" /></>}
            </button>
          </form>

          <div className="mt-8 flex items-center justify-center gap-2 text-[10px] text-gray-600 font-bold uppercase tracking-widest">
            <ShieldCheck className="w-4 h-4" /> Secured by Firebase
          </div>
        </div>
      </div>

    </div>
  );
}

export default Login;
